import boto3
import json
from typing import Dict, Any
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SQSPiiPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        """
        Initialize SQS publisher for PII data
        """
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        
    def send_pii_message(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        """
        Send PII data message to SQS queue
        """
        try:
            # Validate PII data
            self._validate_pii_data(user_data)
            
            # Send message to SQS
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                Message=json.dumps(user_data),
                MessageAttributes={
                    'MessageType': {
                        'StringValue': 'PII_DATA',
                        'DataType': 'String'
                    },
                    'Timestamp': {
                        'StringValue': str(int(time.time())),
                        'DataType': 'Number'
                    }
                }
            )
            
            logger.info(f"PII message sent successfully. MessageId: {response['MessageId']}")
            return response
            
        except Exception as e:
            logger.error(f"Failed to send PII message: {str(e)}")
            raise
            
    def _validate_pii_data(self, user_data: Dict[str, Any]) -> None:
        """
        Validate PII data before sending
        """
        required_fields = ['email', 'phone', 'address']
        for field in required_fields:
            if field not in user_data:
                raise ValueError(f"Missing required PII field: {field}")
                
        # Basic validation
        if not isinstance(user_data['email'], str) or '@' not in user_data['email']:
            raise ValueError("Invalid email format")
            
        if not isinstance(user_data['phone'], str) or not user_data['phone'].isdigit():
            raise ValueError("Invalid phone number format")
            
        if not isinstance(user_data['address'], dict):
            raise ValueError("Invalid address format")

